CREATE OR REPLACE FUNCTION fpb_check_loan_clear_status (as_conno char) RETURNS integer AS $body$
DECLARE

li_count integer;

BEGIN
    select 	count(*)
    into STRICT		li_count
    from  sc_lon_m_loan_request , sc_lon_m_loan_history
    where	sc_lon_m_loan_request.loan_requestment_no = sc_lon_m_loan_history.loan_requestment_no
    and		sc_lon_m_loan_history.loan_contract_no = as_conno
    and		sc_lon_m_loan_history.clear_target = '1'
    and		sc_lon_m_loan_request.approve_status <> '0'
;
    return li_count;
  exception when others then return 0;

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
